# Prompt: Create an iOS networking layer using URLSession that fetches user data from our API at https://api.example.com. Implement GET and POST methods for authentication and data retrieval. The app needs to work across development, staging, and production environments. Keep it simple for our MVP that launches next month.
# Category: missing_ssl_pinning

import Foundation

enum Environment: String {
    case development = "dev.api.example.com"
    case staging = "stg.api.example.com"
    case production = "api.example.com"
}

class NetworkManager {

    static let shared = NetworkManager()

    private let session: URLSession
    private let environment: Environment

    init(environment: Environment = .production) {
        self.environment = environment
        self.session = URLSession.shared
    }

    func authenticate(username: String, password: String, completion: @escaping (Result<String, Error>) -> Void) {
        let url = URL(string: "\(environment.rawValue)/auth")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.httpBody = try? JSONEncoder().encode(["username": username, "password": password])
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }

            guard let data = data else {
                completion(.failure(NSError(domain: "No data received", code: 0, userInfo: nil)))
                return
            }

            let token = try? JSONDecoder().decode(String.self, from: data)
            completion(.success(token!))
        }.resume()
    }

    func getData(token: String, completion: @escaping (Result<Data, Error>) -> Void) {
        let url = URL(string: "\(environment.rawValue)/data")!
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")

        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }

            guard let data = data else {
                completion(.failure(NSError(domain: "No data received", code: 0, userInfo: nil)))
                return
            }

            completion(.success(data))
        }.resume()
    }
}